// Convertit un code OWM en index 0-3 (sun/rain/snow/storm)
static inline uint8_t owm_to_anim_code(int owm_id) {
    if (owm_id >= 200 && owm_id < 300) return 3; // orage
    if (owm_id >= 300 && owm_id < 700) return 1; // pluie/bruine
    if (owm_id >= 700 && owm_id < 800) return 1; // brume -> pluie
    if (owm_id == 800)                 return 0; // ciel clair
    if (owm_id >= 801 && owm_id < 900) return 0; // nuageux -> soleil
    if (owm_id >= 600 && owm_id < 700) return 2; // neige
    return 0;
}

// code: 0=sun 1=rain 2=snow 3=storm
static inline void van_anim_set_weather(uint8_t slot, uint8_t code) {
    static const lv_img_dsc_t** weather_frames[] = {
        (const lv_img_dsc_t**)frames_weather_sun,
        (const lv_img_dsc_t**)frames_weather_rain,
        (const lv_img_dsc_t**)frames_weather_snow,
        (const lv_img_dsc_t**)frames_weather_storm,
    };
    static const uint8_t weather_counts[] = {
        FRAMES_WEATHER_SUN_COUNT,
        FRAMES_WEATHER_RAIN_COUNT,
        FRAMES_WEATHER_SNOW_COUNT,
        FRAMES_WEATHER_STORM_COUNT,
    };
    static const uint32_t weather_periods[] = {150, 120, 180, 80};
    if (code > 3 || slot > 2) return;
    lvgl_anim_set_frames(ANIM_IDX_WEATHER0 + slot,
        weather_frames[code], weather_counts[code], weather_periods[code]);
}

